const html = $input.first().json.data;
if (!html || html.length < 100) {
  return [{ attendanceRecords: [], currentSubjects: {}, emptyHTML: true }];
}
const records = [];
const rowPattern = /<tr[^>]*>([\s\S]*?)<\/tr>/gi;
let rowMatch;
let isHeader = true;
while ((rowMatch = rowPattern.exec(html)) !== null) {
  if (isHeader) { isHeader = false; continue; }
  const rowHtml = rowMatch[1];
  const cells = [];
  const cellPattern = /<t[dh][^>]*>([\s\S]*?)<\/t[dh]>/gi;
  let cellMatch;
  while ((cellMatch = cellPattern.exec(rowHtml)) !== null) {
    const cellText = cellMatch[1].replace(/<[^>]+>/g, "").replace(/&nbsp;/gi, "").replace(/&amp;/gi, "&").trim();
    cells.push(cellText);
  }
  if (cells.length >= 4) {
    const subject = cells[0] || "";
    if (subject && subject !== "Subject" && subject !== "Course") {
      const total = parseInt(cells[cells.length - 3], 10);
      const attended = parseInt(cells[cells.length - 2], 10);
      const perc = parseFloat(cells[cells.length - 1]) || 0;
      records.push({ subject, totalClasses: total || 0, attendedClasses: attended || 0, percentage: perc });
    }
  }
}
const currentSubjects = {};
for (const r of records) { currentSubjects[r.subject] = r; }
return [{ attendanceRecords: records, currentSubjects }];

const staticData = await getWorkflowStaticData("workflow");
const items = $input.all();
if (!items.length) return [{ changes: [], hasChanges: false }];
const currentRecords = items[0].json.attendanceRecords || [];
const prevSubjects = staticData.subjects || {};
const changes = [];
for (const record of currentRecords) {
  const prev = prevSubjects[record.subject];
  if (!prev) {
    changes.push({ type: "new", subject: record.subject, totalClasses: record.totalClasses, attendedClasses: record.attendedClasses, percentage: record.percentage, oldPercentage: null });
  } else if (prev.totalClasses !== record.totalClasses || prev.attendedClasses !== record.attendedClasses || prev.percentage !== record.percentage) {
    changes.push({ type: "updated", subject: record.subject, totalClasses: record.totalClasses, attendedClasses: record.attendedClasses, percentage: record.percentage, oldPercentage: prev.percentage, oldTotalClasses: prev.totalClasses, oldAttendedClasses: prev.attendedClasses });
  }
}
for (const subj of Object.keys(prevSubjects)) {
  if (!currentRecords.find(r => r.subject === subj)) {
    changes.push({ type: "removed", subject: subj, totalClasses: 0, attendedClasses: 0, percentage: 0, oldPercentage: prevSubjects[subj].percentage });
  }
}
staticData.subjects = {};
for (const r of currentRecords) { staticData.subjects[r.subject] = r; }
await staticData.save();
if (changes.length > 0) {
  let message = "";
  for (const c of changes) {
    if (c.type === "new") { message += "New: " + c.subject + " - " + c.attendedClasses + "/" + c.totalClasses + " (" + c.percentage + "%)\n"; }
    else if (c.type === "updated") { message += "Updated: " + c.subject + ": " + c.oldPercentage + "% -> " + c.percentage + "% (" + c.attendedClasses + "/" + c.totalClasses + ")\n"; }
    else { message += "Removed: " + c.subject + " (was " + c.oldPercentage + "%)\n"; }
  }
  return [{ changes, hasChanges: true, message: message.trim() }];
}
return [{ changes: [], hasChanges: false }];

