const items = $input.all();
const results = [];

for (const item of items) {
  // Check if the request succeeded
  if (item.json && item.json.data && item.json.data.Media) {
    const media = item.json.data.Media;
    results.push({
      json: {
        anime_id: media.id,
        title: media.title.english || media.title.romaji,
        title_romaji: media.title.romaji,
        status: media.status,
        episodes: media.episodes,
        next_episode: media.nextAiringEpisode?.episode || null,
        next_airing_at: media.nextAiringEpisode?.airingAt || null,
        season: media.season,
        season_year: media.seasonYear,
        format: media.format,
        source: 'hardcoded',
        relations: media.relations?.edges || []
      }
    });
  }
  // If request failed, we skip this item (it won't be processed further)
}

return results;

const allAnime = $input.all();
const trackedAnime = $('Get Tracked Anime').all();
const now = Math.floor(Date.now() / 1000);
const todayStart = Math.floor(new Date().setHours(0, 0, 0, 0) / 1000);
const todayEnd = Math.floor(new Date().setHours(23, 59, 59, 999) / 1000);

// Build tracker map
const trackerMap = {};
for (const track of trackedAnime) {
  trackerMap[track.json.anime_id] = track.json;
}

const notifications = [];

for (const anime of allAnime) {
  const data = anime.json;
  const tracked = trackerMap[data.anime_id];

  // Check for new episode airing today
  if (data.status === 'RELEASING' && data.next_airing_at) {
    if (data.next_airing_at >= todayStart && data.next_airing_at <= todayEnd) {
      const lastNotified = tracked?.last_notified_episode || 0;
      if (data.next_episode > lastNotified) {
        const airDate = new Date(data.next_airing_at * 1000);
        notifications.push({
          json: {
            notification_type: 'episode',
            title: data.title,
            episode: data.next_episode,
            air_date: airDate.toLocaleString('en-IN', { timeZone: 'Asia/Kolkata', weekday: 'long', day: 'numeric', month: 'long', hour: '2-digit', minute: '2-digit' }),
            link: 'https://anilist.co/anime/' + data.anime_id,
            tracker_update: {
              anime_id: data.anime_id,
              title: data.title,
              last_notified_episode: data.next_episode,
              status: data.status,
              current_season: data.season_year,
              last_checked: new Date().toISOString()
            }
          }
        });
      }
    }
  }

  // Check for new season (sequel)
  if (data.relations) {
    for (const relation of data.relations) {
      if (relation.relationType === 'SEQUEL') {
        const sequel = relation.node;
        if (sequel.status === 'RELEASING' || sequel.status === 'NOT_YET_RELEASED') {
          const sequelTracked = trackerMap[sequel.id];
          if (!sequelTracked) {
            // New season detected!
            notifications.push({
              json: {
                notification_type: 'new_season',
                title: sequel.title.english || sequel.title.romaji,
                parent_title: data.title,
                season: sequel.season + ' ' + sequel.season_year,
                link: 'https://anilist.co/anime/' + sequel.id,
                tracker_update: {
                  anime_id: sequel.id,
                  title: sequel.title.english || sequel.title.romaji,
                  last_notified_episode: 0,
                  status: sequel.status,
                  current_season: sequel.season_year,
                  last_checked: new Date().toISOString()
                }
              }
            });
          }
        }
      }
    }
  }

  // Check for season ended
  if (data.status === 'FINISHED' && tracked && tracked.status === 'RELEASING') {
    notifications.push({
      json: {
        notification_type: 'season_ended',
        title: data.title,
        episodes: data.episodes,
        link: 'https://anilist.co/anime/' + data.anime_id,
        tracker_update: {
          anime_id: data.anime_id,
          title: data.title,
          last_notified_episode: data.last_notified_episode || 0,
          status: data.status,
          current_season: data.season_year,
          last_checked: new Date().toISOString()
        }
      }
    });
  }
}

return notifications;

