return updates;

const stations = ['Aluva','Pulinchodu','Companypady','Ambattukavu','Muttom','Kalamassery','Cochin University','Pathadipalam','Edappally','Changampuzha Park','Palarivattom','JLN Stadium','Kaloor','Lissie','MG Road','Maharaja’s College','Ernakulam South','Kadavanthra','Elamkulam','Vyttila','Thaikoodam','Petta','Vadakkekotta','SN Junction','Tripunithura'];
const aliases = {'edapally':'Edappally','edappaly':'Edappally','m g road':'MG Road','mgroad':'MG Road','maharajas':'Maharaja’s College','maharajas college':'Maharaja’s College','ernakulam south':'Ernakulam South','south':'Ernakulam South','jln':'JLN Stadium','stadium':'JLN Stadium','sn junction':'SN Junction','tripunithura terminal':'Tripunithura'};
const norm = s => String(s || '').toLowerCase().replace(/[^a-z0-9]+/g,' ').trim();
const q = norm(query.station); const exact = aliases[q] || stations.find(s => norm(s) === q);
if (exact) return JSON.stringify({resolved: exact, confidence: 'high'});
const score = s => { const a=norm(s); let m=0; for (const c of q) if(a.includes(c)) m++; return m/Math.max(a.length,q.length,1); };
const candidates = stations.map(s=>({station:s,score:score(s)})).sort((a,b)=>b.score-a.score).slice(0,3);
return JSON.stringify({resolved: candidates[0]?.score >= 0.45 ? candidates[0].station : null, confidence: candidates[0]?.score >= 0.7 ? 'medium':'low', candidates});

const item = $input.item.json.data || $input.item.json.body || $input.item.json;

const normalizeNumber = val =>
  String(val ?? '').replace(/^whatsapp:/i, '');

const rawMessage = String(item?.body ?? item?.Body ?? '').trim();
const mediaCount = Number(item?.numMedia ?? item?.NumMedia ?? 0);
const phoneNumber = normalizeNumber(item?.from ?? item?.From ?? '');
const twilioFrom = normalizeNumber(item?.to ?? item?.To ?? '');
const latitude = (item?.latitude ?? item?.Latitude) ? parseFloat(item?.latitude ?? item?.Latitude) : null;
const longitude = (item?.longitude ?? item?.Longitude) ? parseFloat(item?.longitude ?? item?.Longitude) : null;

let userMessage = rawMessage;
if (latitude !== null && longitude !== null) {
  if (!userMessage) {
    userMessage = `[User shared a location: ${latitude}, ${longitude}]`;
  } else {
    userMessage += `\n[User shared a location: ${latitude}, ${longitude}]`;
  }
}

return [{
  json: {
    phoneNumber,
    twilioFrom,
    userMessage,
    mediaCount,
    isTextOnly: mediaCount === 0 && userMessage.length > 0,
    hasLocation: latitude !== null && longitude !== null,
    latitude,
    longitude,
    receivedAt: item?.timestamp ?? $now.toISO(),
  }
}];

const raw = $input.item.json.output ?? $input.item.json.text ?? $input.item.json.message ?? '';
const cleaned = String(raw).replace(/```json/gi, '').replace(/```/g, '').trim();
let intent;
try { intent = JSON.parse(cleaned); } catch(e) { intent = { destination_place: null, destination_is_station: false, origin_place: null, origin_is_station: false, passengers: 1, requested_arrival_time: null, is_location_shared: false, parse_error: true }; }
return [{ json: intent }];

const gtfs = $('Load GTFS').first().json;
const intent = $('Parse Intent').first().json;
const pre = $('Execute Workflow Trigger').first().json;

const stations = gtfs.stations;
const line = gtfs.line;
const schedule = gtfs.schedule;
const fares = gtfs.fares;

const userLat = pre.latitude ? parseFloat(pre.latitude) : null;
const userLon = pre.longitude ? parseFloat(pre.longitude) : null;
const passengers = intent.passengers ?? 1;

// --- IST TIMEZONE FIX ---
const utcNow = new Date();
const now = new Date(utcNow.getTime() + (330 * 60000)); // UTC + 5:30 in milliseconds

function haversine(lat1, lon1, lat2, lon2) {
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = Math.sin(dLat/2)**2 + Math.cos(lat1 * Math.PI/180) * Math.cos(lat2 * Math.PI/180) * Math.sin(dLon/2)**2;
  return R * 2 * Math.asin(Math.sqrt(a));
}

function closestStation(lat, lon) {
  let closest = null;
  let minDist = Infinity;
  for (const [name, data] of Object.entries(stations)) {
    const dist = haversine(lat, lon, data.lat, data.lon);
    if (dist < minDist) {
      minDist = dist;
      closest = { name, ...data, distKm: dist.toFixed(2) };
    }
  }
  return closest;
}

function getRoute(from, to) {
  const fromIdx = line.indexOf(from);
  const toIdx = line.indexOf(to);
  if (fromIdx === -1 || toIdx === -1) return null;
  const direction = fromIdx < toIdx ? "Tripunithura" : "Aluva";
  const stops = fromIdx < toIdx ? line.slice(fromIdx, toIdx + 1) : line.slice(toIdx, fromIdx + 1).reverse();
  return { stops, numStops: stops.length - 1, direction, travelTimeMin: (stops.length - 1) * 2 };
}

function getNextTrains(stationName, count = 3, requestedDepartureTimeStr = null) {
  const station = stations[stationName];
  if (!station) return { next: [], last: null };

  let targetMins;
  if (requestedDepartureTimeStr) {
    const parts = requestedDepartureTimeStr.split(":");
    targetMins = parseInt(parts[0]) * 60 + parseInt(parts[1]);
  } else {
    // using IST now
    targetMins = now.getUTCHours() * 60 + now.getUTCMinutes();
  }

  const entries = (schedule[station.id] || []).map(t => {
    const parts = t.time.split(":");
    return { ...t, totalMins: parseInt(parts[0]) * 60 + parseInt(parts[1]) };
  }).sort((a, b) => a.totalMins - b.totalMins);

  const upcoming = entries.filter(t => t.totalMins >= targetMins);
  const last = entries[entries.length - 1];
  return { next: upcoming.slice(0, count).map(t => t.time.slice(0, 5)), last: last ? last.time.slice(0, 5) : null };
}

function getLeaveBy(trainTime, walkMins = 7) {
  if (!trainTime) return null;
  const [h, m] = trainTime.split(":").map(Number);
  const total = h * 60 + m - walkMins;
  if (total < 0) return "00:00"; // fallback
  return `${Math.floor(total/60)}:${String(total%60).padStart(2,"0")}`;
}

function getFare(from, to, pax) {
  const fromData = stations[from];
  const toData = stations[to];
  if (!fromData || !toData) return 0;
  const key = `${fromData.zone}_${toData.zone}`;
  if (fares[key]) return fares[key] * pax;
  const dist = haversine(fromData.lat, fromData.lon, toData.lat, toData.lon);
  const base = dist <= 2 ? 10 : dist <= 5 ? 20 : dist <= 10 ? 30 : dist <= 15 ? 40 : dist <= 20 ? 50 : 60;
  return base * pax;
}

const hasLocation = userLat !== null && !isNaN(userLat) && userLon !== null && !isNaN(userLon);
if (!hasLocation && !intent.origin_place) {
  return [{ json: { error: "no_location" } }];
}

if (!intent.destination_place || intent.parse_error) {
  return [{ json: { error: "parse_error" } }];
}

let entryStation;
let originLat = userLat, originLon = userLon;

if (intent.origin_is_station && intent.origin_place && stations[intent.origin_place]) {
  entryStation = { name: intent.origin_place, ...stations[intent.origin_place] };
  originLat = entryStation.lat;
  originLon = entryStation.lon;
} else if (intent.origin_place) {
  let originNominatim = null;
  try { originNominatim = $('Resolve Origin').first().json; } catch(e) {}

  if (originNominatim && originNominatim.lat) {
    originLat = parseFloat(originNominatim.lat);
    originLon = parseFloat(originNominatim.lon);
  } else {
    try { 
      const photon = $('Fallback Origin').first().json; 
      if (photon && photon.features && photon.features.length > 0) {
        const coords = photon.features[0].geometry.coordinates;
        originLat = coords[1];
        originLon = coords[0];
      }
    } catch(e) {}
  }

  if (originLat && originLon) {
    entryStation = closestStation(originLat, originLon);
  } else {
    return [{ json: { error: "no_location" } }];
  }
} else {
  // Use GPS
  if (originLat && originLon) {
    entryStation = closestStation(originLat, originLon);
  } else {
    return [{ json: { error: "no_location" } }];
  }
}

let exitStation;
let destLat, destLon, destLabel;

if (intent.destination_is_station) {
  exitStation = { name: intent.destination_place, ...stations[intent.destination_place] };
  destLat = exitStation.lat;
  destLon = exitStation.lon;
  destLabel = intent.destination_place + " Metro Station Kochi";
} else {
  let nominatim = null;
  try { nominatim = $('Resolve Destination').first().json; } catch(e) {}

  if (nominatim && nominatim.lat) {
    destLat = parseFloat(nominatim.lat);
    destLon = parseFloat(nominatim.lon);
  } else {
    try { 
      const photon = $('Fallback Destination').first().json; 
      if (photon && photon.features && photon.features.length > 0) {
        const coords = photon.features[0].geometry.coordinates;
        destLat = coords[1];
        destLon = coords[0];
      }
    } catch(e) {}
  }

  if (destLat && destLon) {
    exitStation = closestStation(destLat, destLon);
    destLabel = intent.destination_place + " Kochi";
  } else {
    return [{ json: { error: "dest_not_found" } }];
  }
}

if (!entryStation || !exitStation) {
  return [{ json: { error: "station_not_found" } }];
}

if (entryStation.name === exitStation.name) {
  return [{ json: { error: "same_station", entryStation: entryStation.name } }];
}

const route = getRoute(entryStation.name, exitStation.name);
const { next: nextTrains, last: lastTrain } = getNextTrains(entryStation.name, 3, intent.requested_departure_time);

// CHECK IF METRO IS CLOSED
if (nextTrains.length === 0 && !intent.requested_departure_time) {
  return [{ json: { error: "metro_closed" } }];
}

const leaveBy = getLeaveBy(nextTrains[0]);
const fare = getFare(entryStation.name, exitStation.name, passengers);

const originSegment = originLat && originLon ? `${originLat},${originLon}` : encodeURIComponent((intent.origin_place ?? entryStation.name) + " Kochi");
const mapsUrl = `https://www.google.com/maps/dir/${originSegment}/${encodeURIComponent(entryStation.name + " Metro Station Kochi")}/${encodeURIComponent(exitStation.name + " Metro Station Kochi")}/${encodeURIComponent(destLabel)}`;

return [{ json: { entryStation: entryStation.name, exitStation: exitStation.name, entryLat: entryStation.lat, entryLon: entryStation.lon, route, nextTrains, lastTrain, leaveBy, fare, passengers, mapsUrl, travelTimeMin: route?.travelTimeMin ?? 0, numStops: route?.numStops ?? 0, error: null } }];

const q = $('Process Query').first().json;

if (q.error === "no_location") {
  return [{ json: { replyMessage: "📍 Please share your live location or tell me which station you're starting from!\n\nExample: _Aluva to Lulu Mall, 2 people_" } }];
}

if (q.error === "parse_error") {
  return [{ json: { replyMessage: "Sorry, I didn't understand that 😅\n\nTry: _Vyttila to Lulu Mall, 2 people_\nOr share your location and tell me where you want to go!" } }];
}

if (q.error === "dest_not_found") {
  return [{ json: { replyMessage: "Sorry, I couldn't find that destination on the map 🗺️\n\nPlease try being a bit more specific (e.g. adding 'Kochi' or a landmark)!" } }];
}

if (q.error === "station_not_found") {
  return [{ json: { replyMessage: "Sorry, I couldn't find a metro station near that location. 🚇" } }];
}

if (q.error === "same_station") {
  return [{ json: { replyMessage: "📍 You are already at " + q.entryStation + " station! You don't need a metro for this trip." } }];
}

if (q.error === "metro_closed") {
  return [{ json: { replyMessage: "🌙 The metro is currently closed (trains run from 6:00 AM to 11:20 PM). What time do you plan to travel tomorrow so I can find the right trains for you?" } }];
}

let weatherLine = "";
try {
  const w = $('Get Weather').first().json;
  const condition = w?.weather?.[0]?.main?.toLowerCase() ?? "";
  if (condition.includes("rain") || condition.includes("drizzle") || condition.includes("thunder")) {
    weatherLine = `\n🌧 *Rain alert* — ${w.weather[0].description}. Add buffer time for walking.\n`;
  }
} catch(e) {}

const lastTrainWarn = q.lastTrain ? `⚠️ Last train: ${q.lastTrain}\n` : "";
const nextTrainDisplay = q.nextTrains?.[0] ?? "No trains available";
const leaveByDisplay = q.leaveBy ?? "N/A";

const reply = `🚇 *MetroMind Trip Plan*

📍 ${q.entryStation} → ${q.exitStation} (Green Line)
🕙 Next train: ${nextTrainDisplay} (leave by ${leaveByDisplay})
⏱ ${q.travelTimeMin} min | ${q.numStops} stops
${lastTrainWarn}${weatherLine}
🗺 Full journey map:
${q.mapsUrl}

_Powered by MetroMind × KMRL Open Data_`;

return [{ json: { replyMessage: reply } }];
